// isPrivateIP checks if an IP address is in a private or restricted range to prevent SSRF.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
		return true
	}
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 100.64.0.0/10 (CGNAT)
		if ip4[0] == 100 && ip4[1] >= 64 && ip4[1] <= 127 {
			return true
		}
		// 169.254.0.0/16 (Link-local)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		return false
	}
	if ip6 := ip.To16(); ip6 != nil {
		// ULA: fc00::/7
		if (ip6[0] & 0xfe) == 0xfc {
			return true
		}
	}
	return false
}

// Global HTTP client to reuse connection pools and enforce SSRF protection.
var httpClient = &fasthttp.Client{
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 10 * time.Second,
	MaxConnsPerHost:     100,
	MaxResponseBodySize: 2 * 1024 * 1024, // Limit to 2MB to prevent OOM
	Dial: func(addr string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			host = addr
			port = "80"
		}
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, err
		}
		var targetIP net.IP
		for _, ip := range ips {
			if !isPrivateIP(ip) {
				targetIP = ip
				break
			}
		}
		if targetIP == nil {
			return nil, fmt.Errorf("SSRF protection: access to %s is denied", host)
		}
		// Dial using the resolved IP to prevent DNS rebinding attacks.
		return fasthttp.DialDualStack(net.JoinHostPort(targetIP.String(), port))
	},
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		sendJSONError(ctx, "Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		sendJSONError(ctx, "Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		sendJSONError(ctx, "URL is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		sendJSONError(ctx, "Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		sendJSONError(ctx, "URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Execute request with redirect support. Every hop is checked by the Dial function.
	if err := httpClient.DoRedirects(freq, res, 10); err != nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		sendJSONError(ctx, fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(res.Body()))
	if err != nil {
		sendJSONError(ctx, "Failed to parse HTML", fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusOK)
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}
	_ = json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if title == "" {
					title = extractText(n)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					if key == "name" || key == "property" {
						name = strings.ToLower(attr.Val)
					} else if key == "content" {
						content = attr.Val
					}
				}
				if (name == "description" || name == "og:description") && description == "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

// extractText recursively joins all text nodes under an element.
func extractText(n *html.Node) string {
	var buf strings.Builder
	var f func(*html.Node)
	f = func(node *html.Node) {
		if node.Type == html.TextNode {
			buf.WriteString(node.Data)
		}
		for c := node.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(n)
	return buf.String()
}

// sendJSONError helper to return consistent JSON error responses.
func sendJSONError(ctx *fasthttp.RequestCtx, message string, code int) {
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(code)
	resp := PreviewResponse{Error: message}
	_ = json.NewEncoder(ctx).Encode(resp)
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		if string(ctx.Path()) == "/preview" {
			FetchURLPreview(ctx)
		} else {
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}
	fmt.Println("Server starting on :8080...")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		fmt.Printf("Server failed: %v\n", err)
	}
}

