package main

import (
	"bytes"
	"encoding/json"
	"errors"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// httpClient is a reused fasthttp.Client with security configurations.
var httpClient = &fasthttp.Client{
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 30 * time.Second,
	// MaxResponseBodySize prevents OOM by limiting the size of the response we read.
	MaxResponseBodySize: 1024 * 1024, // 1MB
	// Dial is customized to prevent SSRF (Server-Side Request Forgery).
	Dial: safeDial,
}

// isSafeIP checks if an IP address is a public, non-reserved address.
func isSafeIP(ip net.IP) bool {
	// IsGlobalUnicast returns true for public and private unicast IPs.
	// It returns false for loopback, link-local, and multicast.
	// IsPrivate returns true for RFC1918 and RFC4193 (ULA) ranges.
	return ip.IsGlobalUnicast() && !ip.IsPrivate()
}

// safeDial resolves the hostname and ensures the connection is only made to public IPs.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	var ips []net.IP
	if ip := net.ParseIP(host); ip != nil {
		ips = []net.IP{ip}
	} else {
		// Resolve the hostname to IPs.
		ips, err = net.LookupIP(host)
		if err != nil {
			return nil, err
		}
	}

	// Try each resolved IP, only connecting to safe ones.
	// This prevents DNS rebinding by dialing the specific IP address directly.
	for _, ip := range ips {
		if !isSafeIP(ip) {
			continue
		}
		return net.DialTimeout("tcp", net.JoinHostPort(ip.String(), port), 5*time.Second)
	}

	return nil, errors.New("access forbidden: no safe public IP address found")
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// DoRedirects follows redirects while still using our safeDial for each hop.
	if err := httpClient.DoRedirects(freq, res, 10); err != nil {
		if err == fasthttp.ErrBodyTooLarge {
			ctx.Error("Response body too large", fasthttp.StatusRequestEntityTooLarge)
		} else {
			ctx.Error("Failed to fetch URL content", fasthttp.StatusBadGateway)
		}
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error("Unexpected status code from target", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(res.Body()))
	if err != nil {
		ctx.Error("Failed to parse HTML content", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

// parseHTMLPreview extracts title and meta description from HTML using a proper parser.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		// Extract Title
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
		}

		// Extract Meta Description (handling both standard and OpenGraph fallback)
		if n.Type == html.ElementNode && n.Data == "meta" {
			var isDesc bool
			var content string
			for _, attr := range n.Attr {
				key := strings.ToLower(attr.Key)
				val := strings.ToLower(attr.Val)
				if (key == "name" || key == "property") && (val == "description" || val == "og:description") {
					isDesc = true
				} else if key == "content" {
					content = attr.Val
				}
			}
			if isDesc && description == "" {
				description = strings.TrimSpace(content)
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description, nil
}

func main() {
	// Example server setup
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		panic(err)
	}
}

