	if matches := descriptionRegex.FindStringSubmatch(bodyStr); len(matches) > 1 {
		description = strings.TrimSpace(matches[1])
	} else if matches := descriptionRegexAlt.FindStringSubmatch(bodyStr); len(matches) > 1 {
		description = strings.TrimSpace(matches[1])
	}

	// Return result
	res := ResponseBody{
		Title:       title,
		Description: description,
	}
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(res)
}

