// Security Configuration
var (
	maxBodySize = 1024 * 1024 // 1MB
	readTimeout = 5 * time.Second

	// privateIPBlocks defines ranges that should not be accessed (SSRF protection).
	privateIPBlocks = func() []*net.IPNet {
		var blocks []*net.IPNet
		for _, cidr := range []string{
			"127.0.0.0/8",    // IPv4 loopback
			"10.0.0.0/8",     // RFC1918
			"172.16.0.0/12",  // RFC1918
			"192.168.0.0/16", // RFC1918
			"100.64.0.0/10",  // CGNAT
			"169.254.0.0/16", // Link-local
			"::1/128",        // IPv6 loopback
			"fc00::/7",       // IPv6 ULA
			"fe80::/10",      // IPv6 Link-local
		} {
			_, block, _ := net.ParseCIDR(cidr)
			blocks = append(blocks, block)
		}
		return blocks
	}()

	// httpClient is reused for performance and configured for security.
	httpClient = &fasthttp.Client{
		Name:                "URLPreviewBot/1.0",
		ReadTimeout:         readTimeout,
		WriteTimeout:        readTimeout,
		MaxIdleConnDuration: 30 * time.Second,
		MaxConnsPerHost:     10,
		Dial:                ssrfSafeDialer,
		MaxResponseBodySize: maxBodySize,
	}
)

// isSafeIP checks if an IP is public and safe to access.
func isSafeIP(ip net.IP) bool {
	if ip == nil || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
		return false
	}
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return false
		}
	}
	return true
}

// ssrfSafeDialer prevents SSRF by validating IPs before dialing.
func ssrfSafeDialer(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	var targetIP net.IP
	for _, ip := range ips {
		if isSafeIP(ip) {
			targetIP = ip
			break
		}
	}

	if targetIP == nil {
		return nil, fmt.Errorf("access to internal or private IP denied")
	}

	// Dial the specific IP to prevent DNS rebinding attacks.
	return net.DialTimeout("tcp", net.JoinHostPort(targetIP.String(), port), 5*time.Second)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		ctx.Error("Invalid URL or scheme", fasthttp.StatusBadRequest)
		return
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")

	if err := httpClient.DoRedirects(freq, res, 5); err != nil {
		ctx.Error("Failed to fetch URL preview", fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error("Target returned non-200 status", fasthttp.StatusBadGateway)
		return
	}

	contentType := string(res.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("Target is not an HTML page", fasthttp.StatusBadRequest)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(res.Body()))
	if err != nil {
		ctx.Error("Failed to parse content", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (string, string, error) {
	// Read a limited portion of the body for parsing.
	b, err := io.ReadAll(io.LimitReader(r, int64(maxBodySize)))
	if err != nil {
		return "", "", err
	}
	htmlStr := string(b)

	return extractTitle(htmlStr), extractDescription(htmlStr), nil
}

func extractTitle(h string) string {
	lower := strings.ToLower(h)
	start := strings.Index(lower, "<title>")
	if start == -1 {
		return ""
	}
	end := strings.Index(lower[start:], "</title>")
	if end == -1 {
		return ""
	}
	return html.UnescapeString(strings.TrimSpace(h[start+7 : start+end]))
}

func extractDescription(h string) string {
	lower := strings.ToLower(h)
	// Common patterns for description
	idx := strings.Index(lower, "name=\"description\"")
	if idx == -1 {
		idx = strings.Index(lower, "property=\"og:description\"")
	}
	if idx == -1 {
		return ""
	}

	tagStart := strings.LastIndex(lower[:idx], "<meta")
	if tagStart == -1 {
		return ""
	}
	tagEnd := strings.Index(lower[tagStart:], ">")
	if tagEnd == -1 {
		return ""
	}

	tag := h[tagStart : tagStart+tagEnd+1]
	return extractAttribute(tag, "content")
}

func extractAttribute(tag, attr string) string {
	lowerTag := strings.ToLower(tag)
	search := attr + "=\""
	idx := strings.Index(lowerTag, search)
	if idx == -1 {
		search = attr + "='"
		idx = strings.Index(lowerTag, search)
	}
	if idx == -1 {
		return ""
	}

	val := tag[idx+len(search):]
	endIdx := strings.IndexAny(val, "\"'")
	if endIdx == -1 {
		return ""
	}
	return html.UnescapeString(val[:endIdx])
}

