		sendError(ctx, "Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// 2. Parse JSON Body
	var reqBody PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		sendError(ctx, "Invalid JSON body", fasthttp.StatusBadRequest)
