func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set response type to JSON
	ctx.SetContentType("application/json")

	// Only allow POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Method not allowed"})
		return
	}

	// Parse request body
	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid JSON body"})
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "URL is required"})
		return
	}

	// Prepare request and response objects
	request := fasthttp.AcquireRequest()
	response := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(request)
	defer fasthttp.ReleaseResponse(response)

	request.SetRequestURI(req.URL)

	// Validate scheme
	scheme := string(request.URI().Scheme())
	if scheme != "http" && scheme != "https" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid URL scheme. Only http and https are supported."})
		return
	}

	request.Header.SetMethod(fasthttp.MethodGet)
