package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// isPrivateIP checks if an IP address belongs to a private or local range to prevent SSRF.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168) ||
			(ip4[0] == 169 && ip4[1] == 254)
	}
	if len(ip) == net.IPv6len {
		// Check for Unique Local Address (fc00::/7)
		return (ip[0] & 0xfe) == 0xfc
	}
	return false
}

// httpClient is reused for performance, following fasthttp best practices.
// It includes a custom dialer to prevent SSRF by validating resolved IP addresses.
var httpClient = &fasthttp.Client{
	Dial: func(addr string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			host = addr
			port = "80"
		}

		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, err
		}

		for _, ip := range ips {
			if isPrivateIP(ip) {
