	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// DoRedirects uses our safeDial for every hop in the redirect chain
	if err := httpClient.DoRedirects(freq, res, 5); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(res.Body()))
	if err != nil {
		ctx.Error("Failed to parse page content", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		// Extract Title
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = n.FirstChild.Data
			}
		}

		// Extract Meta Description
		if n.Type == html.ElementNode && n.Data == "meta" {
			var isDesc bool
			var content string
			for _, attr := range n.Attr {
				key := strings.ToLower(attr.Key)
				val := strings.ToLower(attr.Val)
				if (key == "name" || key == "property") && (val == "description" || val == "og:description") {
					isDesc = true
				}
				if key == "content" {
					content = attr.Val
				}
			}
			if isDesc && description == "" {
				description = content
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

