}

// Regular expressions to extract title and meta description from HTML.
// (?is) flag: i for case-insensitive, s to allow the dot (.) to match newline characters.
var (
	titleRegex       = regexp.MustCompile(`(?is)<title[^>]*>(.*?)</title>`)
	descriptionRegex = regexp.MustCompile(`(?is)<meta[^>]*name=["']description["'][^>]*content=["'](.*?)["'][^>]*>`)
	descAltRegex     = regexp.MustCompile(`(?is)<meta[^>]*content=["'](.*?)["'][^>]*name=["']description["'][^>]*>`)
)

// FetchURLPreview is a fasthttp handler that fetches a URL and extracts metadata.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set response content type to JSON
	ctx.SetContentType("application/json")

	// Ensure the request method is POST
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: "Method not allowed. Use POST."})
		return
	}

	// Parse the JSON request body
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: "Invalid JSON body"})
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: "URL field is required"})
		return
	}

	// Acquire request and response objects from the fasthttp pool
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	// Configure the fetch request
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	// Set a User-Agent to prevent being blocked by some web servers
	req.Header.Set("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) URLPreviewFetcher/1.0")

	// Requirement: MUST use fasthttp.Client.DoRedirects method.
