		json.NewEncoder(ctx).Encode(ResponseBody{Error: fmt.Sprintf("Failed to fetch content: %v", err)})
		return
	}

	body := resp.Body()

	// Extract the page title
	var title string
	if matches := titleRegex.FindSubmatch(body); len(matches) > 1 {
		// Unescape HTML entities (e.g., &amp; to &) and trim whitespace
		title = strings.TrimSpace(html.UnescapeString(string(matches[1])))
	}

	// Extract the meta description
	var description string
	// Check for standard name="description" format
	if matches := descriptionRegex.FindSubmatch(body); len(matches) > 1 {
		description = strings.TrimSpace(html.UnescapeString(string(matches[1])))
	} else if matches := descAltRegex.FindSubmatch(body); len(matches) > 1 {
		// Check for alternate content="..." name="description" format
		description = strings.TrimSpace(html.UnescapeString(string(matches[1])))
	}

	// Prepare and send the JSON response
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(ResponseBody{
		Title:       title,
		Description: description,
	})
}

func main() {
