// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// isPrivateIP checks if the given IP address is a private, loopback, or link-local address.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
		return true
	}
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168)
	}
	if ip6 := ip.To16(); ip6 != nil {
		// RFC 4193: Unique Local Address
		return (ip6[0] & 0xfe) == 0xfc
	}
	return false
}

// Global httpClient with SSRF protection and response size limits.
var httpClient = &fasthttp.Client{
	Dial: func(addr string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			host = addr
			port = "80"
		}
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, err
		}
		var targetIP net.IP
		for _, ip := range ips {
			if !isPrivateIP(ip) {
				targetIP = ip
				break
			}
		}
		if targetIP == nil {
			return nil, fmt.Errorf("disallowed or unreachable IP address")
		}
		// Connect directly to the resolved IP to prevent DNS rebinding attacks.
		return fasthttp.DialDualStack(net.JoinHostPort(targetIP.String(), port))
	},
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 30 * time.Second,
	MaxConnsPerHost:     100,
	MaxResponseBodySize: 1024 * 1024, // Limit response size to 1MB
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set default content type to JSON
	ctx.SetContentType("application/json; charset=utf-8")

	// Only allow POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Method not allowed"})
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	// Parse JSON body
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid JSON"})
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "URL is required"})
		return
	}

	// Validate URL format and scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid URL format or scheme"})
		return
	}

	// Acquire request and response objects from the pool
	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Fetch the URL following redirects (SSRF protection is in the dialer)
	if err := httpClient.DoRedirects(freq, res, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Failed to fetch URL"})
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: fmt.Sprintf("Unexpected status code: %d", res.StatusCode())})
		return
	}

	// Verify content type is HTML
	contentType := strings.ToLower(string(res.Header.Peek("Content-Type")))
	if !strings.Contains(contentType, "text/html") {
		ctx.SetStatusCode(fasthttp.StatusUnsupportedMediaType)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Not an HTML page"})
		return
	}

	// Parse the HTML content to extract title and description
	title, description, err := parseHTMLPreview(bytes.NewReader(res.Body()))
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Failed to parse HTML content"})
		return
	}

	// Prepare and send the successful response
	resp := PreviewResponse{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML using a tree traversal.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if title == "" {
					var buf strings.Builder
					for c := n.FirstChild; c != nil; c = c.NextSibling {
						if c.Type == html.TextNode {
							buf.WriteString(c.Data)
						}
					}
					title = buf.String()
				}
			case "meta":
				var name, property, content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					if key == "name" {
						name = strings.ToLower(attr.Val)
					} else if key == "property" {
						property = strings.ToLower(attr.Val)
					} else if key == "content" {
						content = attr.Val
					}
				}
				// Priority: name="description" or property="og:description"
				if description == "" {
					if name == "description" || property == "og:description" || property == "twitter:description" {
						description = content
					}
				}
			}
		}
		// Recurse through the node tree
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

