package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"regexp"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

var (
	// privateIPBlocks defines CIDR ranges for private/internal networks to prevent SSRF.
	privateIPBlocks []*net.IPNet

	// dialer is a custom net.Dialer with timeouts.
	dialer = &net.Dialer{
		Timeout:   5 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	// httpClient is a shared fasthttp client with security limits.
	httpClient = &fasthttp.Client{
		Dial:                safeDial,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 30 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: 1024 * 1024 * 2, // Limit response body to 2MB
	}

	// Regex for basic HTML parsing (safer than complex parsers for simple previews).
	titleRegex        = regexp.MustCompile(`(?i)<title[^>]*>([^<]*)</title>`)
	descriptionRegex  = regexp.MustCompile(`(?i)<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
	descriptionRegex2 = regexp.MustCompile(`(?i)<meta[^>]*content=["']([^"']*)["'][^>]*name=["']description["']`)
)

func init() {
	// Initialize private IP ranges (RFC1918, RFC4193, Loopback, Link-local).
	cidrs := []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // RFC1918
		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"169.254.0.0/16", // RFC3927 link-local
		"::1/128",        // IPv6 loopback
		"fe80::/10",      // IPv6 link-local
		"fc00::/7",       // IPv6 unique local addr
	}
	for _, cidr := range cidrs {
		_, block, _ := net.ParseCIDR(cidr)
		privateIPBlocks = append(privateIPBlocks, block)
	}
}

// isPrivateIP checks if an IP belongs to a private or restricted range.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// safeDial is a custom dialer that prevents SSRF by validating resolved IPs.
func safeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Check all resolved IPs; if any are private, block the request.
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("access to private network is prohibited")
		}
	}

	// Dial the first resolved public IP to prevent DNS rebinding attacks.
	return dialer.Dial("tcp", net.JoinHostPort(ips[0].String(), port))
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil || parsedURL.Host == "" {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Follow redirects up to 10 times. safeDial will be called for each redirect.
	if err := httpClient.DoRedirects(freq, res, 10); err != nil {
		ctx.Error("Failed to fetch the provided URL", fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Remote server returned status %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(res.Body()))
	if err != nil {
		ctx.Error("Failed to parse page content", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	respBytes, _ := json.Marshal(resp)
	ctx.SetBody(respBytes)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Read a limited portion of the body for parsing (e.g., first 512KB).
	data, err := io.ReadAll(io.LimitReader(r, 512*1024))
	if err != nil {
		return "", "", err
	}
	content := string(data)

	// Extract Title
	if match := titleRegex.FindStringSubmatch(content); len(match) > 1 {
		title = strings.TrimSpace(match[1])
	}

	// Extract Description (checks both <meta name="description" content="..."> and vice versa)
	if match := descriptionRegex.FindStringSubmatch(content); len(match) > 1 {
		description = strings.TrimSpace(match[1])
	} else if match := descriptionRegex2.FindStringSubmatch(content); len(match) > 1 {
		description = strings.TrimSpace(match[1])
	}

	return title, description, nil
}

