	Dial:                fasthttp.DialDualStack,
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 30 * time.Second,
	MaxConnsPerHost:     100,
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Acquire request and response objects from pool
	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0 (Professional Programmer Task)")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9")

	// Execute request with redirect support
	maxRedirectCounts := 5
	if err := httpClient.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML logic
	// Note: res.Body() is a byte slice. We pass a reader to the HTML parser.
	title, description, err := parseHTMLPreview(bytes.NewReader(res.Body()))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML using golang.org/x/net/html.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var crawler func(*html.Node)
	crawler = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				var name, property, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "property":
						property = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}

				// Look for standard description or OpenGraph description
				if (name == "description" || property == "og:description") && description == "" {
					description = content
				}
				// Also capture og:title if title is still empty
				if property == "og:title" && title == "" {
					title = content
				}
			}
		}

		// Recursively traverse the tree
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			crawler(c)
		}
	}

	crawler(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

func main() {
	// Example server setup
	requestHandler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Unsupported path", fasthttp.StatusNotFound)
		}
	}

	fmt.Println("Server starting on :8080...")
	if err := fasthttp.ListenAndServe(":8080", requestHandler); err != nil {
		fmt.Printf("Error in ListenAndServe: %v\n", err)
	}
}

