	}
	scheme := string(uri.Scheme())
	if scheme != "http" && scheme != "https" {
		sendError(ctx, "Only HTTP and HTTPS are supported", fasthttp.StatusBadRequest)
		return
	}

	// Prepare request and response objects for fasthttp client
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetURI(uri)
	req.Header.SetMethod(fasthttp.MethodGet)
	// Some sites block requests without a User-Agent
	req.Header.Set("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36")

	// Execute request with redirect support (max 10 redirects)
	if err := client.DoRedirects(req, resp, 10); err != nil {
		sendError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(resp.Body())

	// Send successful response
	res := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(res)
}

// parseHTML extracts the <title> and <meta name="description"> from HTML content
func parseHTML(body []byte) (title string, description string) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

	var crawler func(*html.Node)
	crawler = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract Description from Meta tags
			if n.Data == "meta" {
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					val := attr.Val
					if key == "name" {
						nameAttr = strings.ToLower(val)
					}
					if key == "content" {
						contentAttr = val
					}
					// Support OpenGraph description as fallback
					if key == "property" && strings.ToLower(val) == "og:description" && description == "" {
						nameAttr = "description"
					}
				}

				if nameAttr == "description" {
					description = strings.TrimSpace(contentAttr)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			crawler(c)
		}
	}

	crawler(doc)
	return title, description
}

// sendError helper to return JSON error messages
func sendError(ctx *fasthttp.RequestCtx, message string, code int) {
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(code)
	res := PreviewResponse{Error: message}
	json.NewEncoder(ctx).Encode(res)
}

func main() {
	// Define the request handler
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	port := ":8080"
	log.Printf("Server starting on %s", port)
	if err := fasthttp.ListenAndServe(port, handler); err != nil {
		log.Fatalf("Error in ListenAndServe: %v", err)
	}
}

