// isReservedIP checks if an IP address is private, loopback, or reserved for internal use.
func isReservedIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 || // 10.0.0.0/8
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) || // 172.16.0.0/12
			(ip4[0] == 192 && ip4[1] == 168) || // 192.168.0.0/16
			(ip4[0] == 169 && ip4[1] == 254) || // 169.254.0.0/16
			ip4[0] == 0 // 0.0.0.0/8
	}
	if ip16 := ip.To16(); ip16 != nil {
		return (ip16[0] & 0xfe) == 0xfc // fc00::/7 (ULA)
	}
	return false
}

// httpClient is a reusable fasthttp client with SSRF protection and resource limits.
var httpClient = &fasthttp.Client{
	ReadTimeout:              5 * time.Second,
	WriteTimeout:             5 * time.Second,
	MaxIdleConnDuration:      30 * time.Second,
	MaxResponseBodySize:      1024 * 1024, // Limit response to 1MB
	NoDefaultUserAgentHeader: true,
	Dial: func(addr string) (net.Conn, error) {
		host, _, err := net.SplitHostPort(addr)
		if err != nil {
			host = addr
		}
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, err
		}
		for _, ip := range ips {
			if isReservedIP(ip) {
				return nil, fmt.Errorf("SSRF protection: prohibited IP %s", ip.String())
			}
		}
		return fasthttp.DialDualStack(addr)
	},
}

// FetchURLPreview handles POST requests to fetch URL preview information safely.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		sendJSONError(ctx, "Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		sendJSONError(ctx, "URL is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		sendJSONError(ctx, "Invalid URL format", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		sendJSONError(ctx, "URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9")

	// Execute request with redirect support
	if err := httpClient.DoRedirects(freq, res, 5); err != nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		sendJSONError(ctx, fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML from the response body
	title, description, err := parseHTMLPreview(bytes.NewReader(res.Body()))
	if err != nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusOK)
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}
	_ = json.NewEncoder(ctx).Encode(resp)
}

// sendJSONError helper to return errors in a consistent JSON format.
func sendJSONError(ctx *fasthttp.RequestCtx, msg string, code int) {
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(code)
	resp := PreviewResponse{Error: msg}
	_ = json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)
	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				return title, description, nil
			}
			return title, description, z.Err()
		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()
			if t.Data == "title" && title == "" {
				if nextType := z.Next(); nextType == html.TextToken {
					title = strings.TrimSpace(string(z.Text()))
				}
			} else if t.Data == "meta" {
				var name, content string
				for _, attr := range t.Attr {
					key := strings.ToLower(attr.Key)
					if key == "name" || key == "property" {
						name = strings.ToLower(attr.Val)
					} else if key == "content" {
						content = attr.Val
					}
				}
				if description == "" && (name == "description" || name == "og:description") {
					description = strings.TrimSpace(content)
				}
				if title == "" && (name == "title" || name == "og:title") {
					title = strings.TrimSpace(content)
				}
			}
		}
	}
}

func main() {
	fmt.Println("Starting URL Preview server on :8080...")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("Server failed: %v\n", err)
	}
}

