// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

var (
	// Global client to reuse connections and prevent resource exhaustion.
	httpClient = &fasthttp.Client{
		Name:                     "URLPreviewBot/1.0",
		NoDefaultUserAgentHeader: true,
		ReadTimeout:              5 * time.Second,
		WriteTimeout:             5 * time.Second,
		MaxIdleConnDuration:      30 * time.Second,
		MaxResponseBodySize:      1024 * 1024, // Limit response to 1MB to prevent DoS
		Dial:                     ssrfSafeDialer,
	}

	// Regex for basic HTML parsing
	titleRegex       = regexp.MustCompile(`(?i)<title>(.*?)</title>`)
	descriptionRegex = regexp.MustCompile(`(?i)<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
)

// ssrfSafeDialer prevents access to private/internal networks.
func ssrfSafeDialer(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	var targetIP net.IP
	for _, ip := range ips {
		if isPrivateIP(ip) {
			continue
		}
		targetIP = ip
		break
	}

	if targetIP == nil {
		return nil, fmt.Errorf("access to internal or private network is forbidden")
	}

	// Dial the specific IP to prevent DNS rebinding
	dialer := &net.Dialer{
		Timeout:   3 * time.Second,
		KeepAlive: 30 * time.Second,
	}
	return dialer.Dial("tcp", net.JoinHostPort(targetIP.String(), port))
}

// isPrivateIP checks if an IP belongs to a private, loopback, or local range.
func isPrivateIP(ip net.IP) bool {
	return ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsPrivate()
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml")

	// DoRedirects will use our ssrfSafeDialer for every hop
	if err := httpClient.DoRedirects(freq, res, 5); err != nil {
		ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Only parse if it looks like HTML
	contentType := string(res.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("URL is not an HTML page", fasthttp.StatusUnsupportedMediaType)
		return
	}

	title, description := parseHTMLPreview(res.Body())

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML using regex.
func parseHTMLPreview(body []byte) (title, description string) {
	// Extract Title
	if matches := titleRegex.FindSubmatch(body); len(matches) > 1 {
		title = strings.TrimSpace(string(matches[1]))
	}

	// Extract Description
	if matches := descriptionRegex.FindSubmatch(body); len(matches) > 1 {
		description = strings.TrimSpace(string(matches[1]))
	}

	return title, description
}

