	var reqBody PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Invalid JSON body"})
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "URL field is required"})
		return
	}

	// Prepare the request to the target URL
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	// Some sites require a User-Agent to return proper HTML
	req.Header.Set("User-Agent", "fasthttp-url-preview/1.0")

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Fetch the content using DoRedirects as required (max 10 redirects)
	// The 3-second timeout is enforced by the httpClient.ReadTimeout configuration
	if err := httpClient.DoRedirects(req, resp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
