// extractMetadata parses HTML content to extract the <title> and meta description.
func extractMetadata(htmlContent []byte) (string, string) {
	var title, description string
	tokenizer := html.NewTokenizer(strings.NewReader(string(htmlContent)))

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			break
		}

		token := tokenizer.Token()
		switch tokenType {
		case html.StartTagToken:
			// Extract <title>
			if token.Data == "title" {
				if nextType := tokenizer.Next(); nextType == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			}
			// Extract <meta> tags (StartTag)
			if token.Data == "meta" {
				description = parseMetaTag(token, description)
			}
		case html.SelfClosingTagToken:
			// Extract <meta /> tags (SelfClosing)
			if token.Data == "meta" {
				description = parseMetaTag(token, description)
			}
		}
	}
	return title, description
}

// parseMetaTag is a helper to find description content from meta attributes.
func parseMetaTag(token html.Token, currentDesc string) string {
	var nameAttr, contentAttr string
	for _, attr := range token.Attr {
		key := strings.ToLower(attr.Key)
		if key == "name" || key == "property" {
			nameAttr = strings.ToLower(attr.Val)
		}
		if key == "content" {
			contentAttr = attr.Val
		}
	}

	// Prioritize standard description, then og:description if empty.
	if (nameAttr == "description" || nameAttr == "og:description") && currentDesc == "" {
		return contentAttr
	}
	return currentDesc
}

// FetchURLPreview handles POST requests to extract page metadata from a URL.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set default response header
	ctx.SetContentType("application/json")

	// 1. Requirement: Must be a POST request
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		fmt.Fprintf(ctx, `{"error": "Only POST method is allowed"}`)
		return
	}

	// 2. Parse JSON body
	var reqBody PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		fmt.Fprintf(ctx, `{"error": "Invalid JSON body"}`)
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		fmt.Fprintf(ctx, `{"error": "URL field is required"}`)
		return
	}

	// 3. Prepare the HTTP request to the target URL
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	// Set a User-Agent to avoid being blocked by some websites
	req.Header.Set("User-Agent", "fasthttp-url-preview/1.0")

	// 4. Requirement: Use DoRedirects to fetch the content
	// Max 10 redirects is a safe default.
	if err := httpClient.DoRedirects(req, resp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		fmt.Fprintf(ctx, `{"error": "Failed to fetch URL: %s"}`, err.Error())
		return
	}

	// 5. Parse HTML and extract metadata
	title, desc := extractMetadata(resp.Body())

	// 6. Return JSON response
	result := PreviewResponse{
		Title:       title,
		Description: desc,
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(result); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
	}
}

func main() {
