		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		// Error logged by fasthttp
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML using a tokenizer.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)
	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				return title, description, nil
			}
			return title, description, z.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()

			// Extract Title
			if t.Data == "title" && tt == html.StartTagToken {
				if z.Next() == html.TextToken {
					title = strings.TrimSpace(z.Token().Data)
				}
			}

			// Extract Meta Description (standard or OpenGraph)
			if t.Data == "meta" {
				var name, content string
				for _, attr := range t.Attr {
					attrKey := strings.ToLower(attr.Key)
					if attrKey == "name" || attrKey == "property" {
						name = strings.ToLower(attr.Val)
					} else if attrKey == "content" {
						content = attr.Val
					}
				}

				if (name == "description" || name == "og:description") && description == "" {
					description = strings.TrimSpace(content)
				}
			}
		}
		// Stop parsing if both are found to save resources
		if title != "" && description != "" {
			return title, description, nil
		}
	}
}

func main() {
	fmt.Println("Server starting on :8080...")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

