	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// ssrfSafeDialer prevents SSRF by validating the resolved IP address.
// It also protects against DNS rebinding by dialing the resolved IP directly.
func ssrfSafeDialer(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		host = addr
		port = "80"
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			continue
		}
		// Dial the first public IP found to prevent DNS rebinding
		return fasthttp.DialTimeout(net.JoinHostPort(ip.String(), port), 5*time.Second)
	}

	return nil, fmt.Errorf("no public IP addresses found for host %s", host)
}

// isPrivateIP checks if an IP belongs to private, loopback, or link-local ranges.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
		return true
	}
	// Check for RFC 1918 (IPv4) and RFC 4193 (IPv6) private ranges
	if ip.IsPrivate() {
		return true
	}
	return false
}

// httpClient is reused to take advantage of connection pooling.
var httpClient = &fasthttp.Client{
	Name:                "URLPreviewBot/1.0",
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 30 * time.Second,
	MaxConnsPerHost:     5,
	MaxResponseBodySize: 1024 * 512, // Limit body to 512KB to prevent DoS
	Dial:                ssrfSafeDialer,
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")

	// DoRedirects will use the custom safe dialer for every hop
	if err := httpClient.DoRedirects(freq, res, 5); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Ensure we only parse HTML content
	contentType := string(res.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("URL must return text/html", fasthttp.StatusBadRequest)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(res.Body()))
	if err != nil {
		ctx.Error("Failed to parse HTML content", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML using a proper tokenizer.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)
	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				return title, description, nil
			}
			return "", "", z.Err()
		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()
			if t.Data == "title" {
				if z.Next() == html.TextToken {
					if title == "" {
						title = strings.TrimSpace(z.Token().Data)
					}
				}
			}
			if t.Data == "meta" {
				var name, content string
				for _, a := range t.Attr {
					key := strings.ToLower(a.Key)
					if key == "name" || key == "property" {
						name = strings.ToLower(a.Val)
					} else if key == "content" {
						content = a.Val
					}
				}
				// Support standard description and OpenGraph description
				if (name == "description" || name == "og:description") && description == "" {
					description = strings.TrimSpace(content)
				}
				// Fallback title from OpenGraph
				if (name == "title" || name == "og:title") && title == "" {
					title = strings.TrimSpace(content)
				}
			}
		}
	}
}

