// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

var (
	// privateIPBlocks contains CIDR ranges for private/reserved IP addresses.
	privateIPBlocks []*net.IPNet
	// httpClient is reused for performance and connection pooling.
	httpClient *fasthttp.Client
)

func init() {
	// Initialize SSRF protection blocks
	cidrs := []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // RFC1918
		"100.64.0.0/10",  // RFC6598
		"169.254.0.0/16", // RFC3927
		"172.16.0.0/12",  // RFC1918
		"192.0.0.0/24",   // RFC6890
		"192.0.2.0/24",   // RFC5737
		"192.88.99.0/24", // RFC3068
		"192.168.0.0/16", // RFC1918
		"198.18.0.0/15",  // RFC2544
		"198.51.100.0/24",// RFC5737
		"203.0.113.0/24", // RFC5737
		"224.0.0.0/4",    // RFC3171
		"240.0.0.0/4",    // RFC1112
		"255.255.255.255/32",
		"::1/128",   // IPv6 loopback
		"fc00::/7",  // IPv6 unique local addr
		"fe80::/10", // IPv6 link-local addr
	}
	for _, cidr := range cidrs {
		_, block, _ := net.ParseCIDR(cidr)
		privateIPBlocks = append(privateIPBlocks, block)
	}

	// Configure fasthttp.Client with SSRF protection and limits
	httpClient = &fasthttp.Client{
		ReadTimeout:                   10 * time.Second,
		WriteTimeout:                  10 * time.Second,
		MaxIdleConnDuration:           30 * time.Second,
		NoDefaultUserAgentHeader:      true,
		MaxResponseBodySize:           1 * 1024 * 1024, // Limit to 1MB to prevent OOM
		MaxIdemponentCallAttempts:     1,
		Dial: safeDialer,
	}
}

// safeDialer prevents SSRF by checking resolved IPs against private ranges.
func safeDialer(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		host = addr
		port = "80"
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("SSRF protection: access to %s is prohibited", ip.String())
		}
	}

	// Dial the first resolved IP to prevent DNS rebinding attacks
	return net.DialTimeout("tcp", net.JoinHostPort(ips[0].String(), port), 5*time.Second)
}

func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
		return true
	}
	for _, block := range privateIPBlocks {
		if block.Contains(ip) {
			return true
		}
	}
	return false
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		ctx.Error("Invalid URL: must be http or https", fasthttp.StatusBadRequest)
		return
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html")

	if err := httpClient.DoRedirects(freq, res, 5); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Target returned status: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Check content type to avoid processing non-HTML files
	contentType := string(res.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("URL is not an HTML page", fasthttp.StatusUnsupportedMediaType)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(res.Body()))
	if err != nil {
		ctx.Error("Failed to parse page content", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML using a proper parser.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" {
				title = extractText(n)
			} else if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					key := strings.ToLower(attr.Key)
					if key == "name" || key == "property" {
						name = strings.ToLower(attr.Val)
					} else if key == "content" {
						content = attr.Val
					}
				}
				if name == "description" || name == "og:description" {
					if description == "" {
						description = content
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)
	return title, description, nil
}

// extractText helper to get text content from a node.
func extractText(n *html.Node) string {
	var buf strings.Builder
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if c.Type == html.TextNode {
			buf.WriteString(c.Data)
		}
	}
	return strings.TrimSpace(buf.String())
}

