		sendJSONError(ctx, fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	// Send successful JSON response
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

// sendJSONError helper to return consistent JSON error responses.
func sendJSONError(ctx *fasthttp.RequestCtx, message string, statusCode int) {
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(statusCode)
	json.NewEncoder(ctx).Encode(PreviewResponse{Error: message})
}

// parseHTMLPreview extracts title and meta description from HTML using a tokenizer.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)
	var inTitle bool

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			if z.Err() == io.EOF {
				return strings.TrimSpace(title), strings.TrimSpace(description), nil
			}
			return "", "", z.Err()

		case html.StartTagToken:
			t := z.Token()
			if t.Data == "title" {
				inTitle = true
			} else if t.Data == "meta" {
				if d := extractMetaDescription(t); d != "" && description == "" {
					description = d
				}
			}

		case html.SelfClosingTagToken:
			t := z.Token()
			if t.Data == "meta" {
				if d := extractMetaDescription(t); d != "" && description == "" {
					description = d
				}
			}

		case html.TextToken:
			if inTitle {
				title += string(z.Text())
			}

		case html.EndTagToken:
			t := z.Token()
			if t.Data == "title" {
				inTitle = false
			}
		}
	}
}

// extractMetaDescription checks a meta token for standard description or OpenGraph description.
func extractMetaDescription(t html.Token) string {
	var isDesc bool
	var content string
	for _, attr := range t.Attr {
		key := strings.ToLower(attr.Key)
		val := strings.ToLower(attr.Val)
		if (key == "name" && val == "description") || (key == "property" && val == "og:description") {
			isDesc = true
		}
		if key == "content" {
			content = attr.Val
		}
	}
	if isDesc {
		return content
	}
	return ""
}

