// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// Global client for connection reuse. 
// Includes SSRF protection and DoS limits.
var httpClient = &fasthttp.Client{
	Name:                "URLPreviewBot/1.0",
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 30 * time.Second,
	MaxConnsPerHost:     100,
	MaxResponseBodySize: 1024 * 1024, // Limit response to 1MB to prevent DoS
	Dial: func(addr string) (net.Conn, error) {
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			return nil, err
		}

		// Resolve IPs and check for private/loopback addresses (SSRF Protection)
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, err
		}

		for _, ip := range ips {
			if isPrivateIP(ip) {
				return nil, fmt.Errorf("access to private network address %s is prohibited", ip.String())
			}
		}

		// Dial the first resolved safe IP
		dialer := &net.Dialer{
			Timeout: 5 * time.Second,
		}
		return dialer.Dial("tcp", net.JoinHostPort(ips[0].String(), port))
	},
}

// isPrivateIP checks if an IP belongs to a private, loopback, or local range.
func isPrivateIP(ip net.IP) bool {
	return ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsPrivate() || ip.IsUnspecified()
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml")

	// Follow redirects safely (the custom Dial function will be called for each hop)
	if err := httpClient.DoRedirects(freq, res, 5); err != nil {
		ctx.Error("Failed to fetch URL content", fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error("Target URL returned an error status", fasthttp.StatusBadGateway)
		return
	}

	// Only parse if it looks like HTML
	contentType := string(res.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("Target URL is not an HTML page", fasthttp.StatusUnsupportedMediaType)
		return
	}

	title, description := parseHTMLPreview(res.Body())

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	json.NewEncoder(ctx).Encode(resp)
}

var (
	titleRegex       = regexp.MustCompile(`(?i)<title>(.*?)</title>`)
	descriptionRegex = regexp.MustCompile(`(?i)<meta\s+[^>]*name=["']description["'][^>]*content=["']([^"']+)["']`)
	altDescRegex     = regexp.MustCompile(`(?i)<meta\s+[^>]*content=["']([^"']+)["'][^>]*name=["']description["']`)
)

// parseHTMLPreview extracts title and meta description from HTML bytes.
func parseHTMLPreview(body []byte) (title, description string) {
	// Extract Title
	if matches := titleRegex.FindSubmatch(body); len(matches) > 1 {
		title = strings.TrimSpace(string(matches[1]))
	}

	// Extract Description (checking both common attribute orders)
	if matches := descriptionRegex.FindSubmatch(body); len(matches) > 1 {
		description = strings.TrimSpace(string(matches[1]))
	} else if matches = altDescRegex.FindSubmatch(body); len(matches) > 1 {
		description = strings.TrimSpace(string(matches[1]))
	}

	return title, description
}

func main() {
	// Example server setup
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

