// httpClient is configured according to the requirements.
// Requirement: MUST set fasthttp.Client.Dial to fasthttp.DialDualStack.
// Requirement: The timeout when fetching content MUST be 3 seconds.
var httpClient = &fasthttp.Client{
	Dial:         fasthttp.DialDualStack,
	ReadTimeout:  3 * time.Second,
	WriteTimeout: 3 * time.Second,
	// MaxIdleConnDuration helps manage connection pooling efficiently.
	MaxIdleConnDuration: 10 * time.Second,
}

var (
	// Regex for extracting the <title> tag content.
	titleRegex = regexp.MustCompile(`(?is)<title[^>]*>(.*?)</title>`)
	// Regex for extracting <meta name="description" content="...">.
	descRegex1 = regexp.MustCompile(`(?i)<meta\s+[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
	// Regex for extracting <meta content="..." name="description">.
	descRegex2 = regexp.MustCompile(`(?i)<meta\s+[^>]*content=["']([^"']*)["'][^>]*name=["']description["']`)
)

// PreviewRequest defines the structure for the incoming JSON body.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the structure for the outgoing JSON response.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview fetches the provided URL and extracts its title and meta description.
// Signature requirement: func FetchURLPreview(ctx *fasthttp.RequestCtx)
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set the response content type to JSON.
	ctx.SetContentType("application/json")

	// Only allow POST requests.
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString(`{"error":"Method not allowed"}`)
		return
	}

	// Parse the JSON request body.
	var reqBody PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString(`{"error":"Invalid JSON body"}`)
		return
	}

	// Validate the URL field.
	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString(`{"error":"URL field is required"}`)
		return
	}

	// Prepare fasthttp request and response objects.
	req := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(res)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	// Set a common User-Agent to avoid being blocked by some websites.
	req.Header.Set("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36")

	// Requirement: MUST use fasthttp.Client.DoRedirects method.
	// We allow up to 5 redirects.
	err := httpClient.DoRedirects(req, res, 5)

	var result PreviewResponse
	if err != nil {
		result.Error = fmt.Sprintf("Failed to fetch URL: %v", err)
	} else {
		body := res.Body()
		result.Title = strings.TrimSpace(extractTitle(body))
		result.Description = strings.TrimSpace(extractDescription(body))
	}

	// Encode the result as JSON to the response body.
	if err := json.NewEncoder(ctx).Encode(result); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
	}
}

// extractTitle parses the HTML body to find the page title.
func extractTitle(body []byte) string {
	matches := titleRegex.FindSubmatch(body)
	if len(matches) > 1 {
		return string(matches[1])
	}
	return ""
}

// extractDescription parses the HTML body to find the meta description.
func extractDescription(body []byte) string {
	// Check standard name="description" first.
	if matches := descRegex1.FindSubmatch(body); len(matches) > 1 {
		return string(matches[1])
	}
	// Fallback to content="..." name="description" order.
	if matches := descRegex2.FindSubmatch(body); len(matches) > 1 {
		return string(matches[1])
	}
	return ""
}

