					}
				}
			}
		}
	}
	return
}

// getMetaDescription is a helper to extract the content attribute if the meta name is "description".
func getMetaDescription(t html.Token) string {
	var isDescription bool
	var content string

	for _, attr := range t.Attr {
		key := strings.ToLower(attr.Key)
		if key == "name" && strings.ToLower(attr.Val) == "description" {
			isDescription = true
		} else if key == "content" {
			content = attr.Val
		}
	}

	if isDescription {
		return content
	}
	return ""
}

func main() {
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	addr := ":8080"
	log.Printf("Server starting on %s", addr)
	if err := fasthttp.ListenAndServe(addr, handler); err != nil {
